mapper.select:
SELECT user_id AS userId, user_name AS userName, level, power, fame,
       rank_name AS rankName, ranking, nation
FROM hero_rank ORDER BY ranking ASC LIMIT #{offset}, #{limit}

SELECT user_id AS userId, user_name AS userName, level, power, fame,
       rank_name AS rankName, ranking, nation
FROM hero_rank
WHERE ranking BETWEEN #{minRank} AND #{maxRank}
  AND user_id != #{excludeUserId}
ORDER BY RAND()
LIMIT #{limit}

mapper.update:
UPDATE hero_rank SET
    ranking = CASE
        WHEN user_id = #{userA} THEN #{rankB}
        WHEN user_id = #{userB} THEN #{rankA}
    END,
    update_time = #{updateTime}
WHERE user_id IN (#{userA}, #{userB})

UPDATE hero_rank SET
    pending_fame = #{pendingFame}, pending_silver = #{pendingSilver},
    pending_exp = #{pendingExp}, reward_claimed = 0,
    settle_date = #{settleDate}
WHERE user_id = #{userId}

mapper.select:
SELECT id, user_id AS userId, ranking, fame_reward AS fameReward,
       silver_reward AS silverReward, settle_date AS settleDate, create_time AS createTime
FROM hero_rank_reward_log
WHERE user_id = #{userId}
ORDER BY create_time DESC
LIMIT #{limit}
